def minimax(node, maximizing):
    if not isinstance(node, list):
        return node
    if maximizing:
        return max(minimax(child, False) for child in node)
    else:
        return min(minimax(child, True) for child in node)

def alpha_beta(node, alpha, beta, maximizing):
    if not isinstance(node, list):
        return node
    if maximizing:
        value = float('-inf')
        for child in node:
            value = max(value, alpha_beta(child, alpha, beta, False))
            alpha = max(alpha, value)
            if alpha >= beta:
                break  # MIN won't allow this branch
        return value
    else:
        value = float('inf')
        for child in node:
            value = min(value, alpha_beta(child, alpha, beta, True))
            beta = min(beta, value)
            if alpha >= beta:
                break  # MAX already has a better guarantee elsewhere
        return value

tree_a = [[3, 12, 8], [2, 4, 6], [14, 5, 2]]
tree_b = [[[1,8],[5,3]], [[9,2],[4,7]]]

for name, tree in [("A", tree_a), ("B", tree_b)]:
    mm = minimax(tree, True)
    ab = alpha_beta(tree, float('-inf'), float('inf'), True)
    status = "OK" if mm == ab else "MISMATCH"
    print(f"Tree {name}: minimax={mm}, alpha_beta={ab}  [{status}]")
